export interface Difficulty { min: number; max: number; }
function d(min: number, max: number): Difficulty { return { min, max }; }

export interface MetricsScenario {
  product: string; metricName: string; metricChange: string; context: string;
  options: { text: string; correct: boolean; note: string }[];
  difficulty: Difficulty;
}
export interface GuesstimateScenario {
  question: string; referenceAnswer: number; referenceMethod: string;
  difficulty: Difficulty;
}
export interface PrioritizeScenario {
  stakes: string; constraint: string;
  items: { id: string; title: string; desc: string; hiddenCost: string }[];
  strongRankingLooksLike: string;
  difficulty: Difficulty;
}
export interface ProductSenseScenario {
  prompt: string; context: string;
  difficulty: Difficulty;
}
export interface ABScenario {
  variantA: { label: string; users: number; conversions: number; rate: string };
  variantB: { label: string; users: number; conversions: number; rate: string };
  pValue: string; guardrails: { metric: string; control: string; variant: string; concern: boolean; explanation?: string }[];
  correctAnswer: string; correctLabel: string; explanation: string; trap: string;
  difficulty: Difficulty;
}
export interface CrisisScenario {
  incident: string; blastRadius: string; signals: string[];
  bestTechId: string; bestCommsId: string; explanation: string;
  difficulty: Difficulty;
}
export interface NorthStarScenario {
  businessModel: string; context: string; candidates: string[]; best: string;
  gamblingRisks: string[]; strongAnswerLooksLike: string;
  difficulty: Difficulty;
}
export interface StandoffScenario {
  stakeholder: string; openingLine: string; underlyingConcern: string;
  turns: { prompt: string; options: { line: string; trustDelta: number; trulyGood: boolean }[] }[];
  finalDebrief: string;
  difficulty: Difficulty;
}
export interface InterviewScenario {
  product: string; researchGoal: string;
  transcript: { speaker: string; text: string }[];
  temptingMisreads: string; realInsight: string; strongAnswerLooksLike: string;
  difficulty: Difficulty;
}
export interface ScopeScenario {
  product: string; ask: string; engineerEstimate: string; engineerReasoning: string;
  stakes: string; strongAnswerLooksLike: string;
  difficulty: Difficulty;
}
export interface QueryScenario {
  businessQuestion: string; query: string; bugType: string;
  bugExplanation: string; whatWentUnnoticed: string; correctedQuery: string;
  difficulty: Difficulty;
}
export interface PostmortemScenario {
  incident: string; whatWentWell: string[]; whatWentWrong: string[]; actionItems: string[];
  difficulty: Difficulty;
}
export interface TrustSafetyScenario {
  issue: string; severity: string; contentCategory: string; policyCategories: string[];
  difficulty: Difficulty;
}

