function pick<T>(arr: T[]): T {
  return arr[Math.floor(Math.random() * arr.length)];
}

export function pickForPool(poolKey: string, tier: number): any {
  switch (poolKey) {
    case 'metrics': return pick(metricsPool.filter(s => s.difficulty.min <= tier && s.difficulty.max >= tier));
    case 'guesstimate': return pick(guesstimatePool.filter(s => s.difficulty.min <= tier && s.difficulty.max >= tier));
    case 'prioritize': return pick(prioritizePool.filter(s => s.difficulty.min <= tier && s.difficulty.max >= tier));
    case 'productSense': return pick(productSensePool.filter(s => s.difficulty.min <= tier && s.difficulty.max >= tier));
    case 'abTest': return pick(abTestPool.filter(s => s.difficulty.min <= tier && s.difficulty.max >= tier));
    case 'crisis': return pick(crisisPool.filter(s => s.difficulty.min <= tier && s.difficulty.max >= tier));
    case 'northStar': return pick(northStarPool.filter(s => s.difficulty.min <= tier && s.difficulty.max >= tier));
    case 'standoff': return pick(standoffPool.filter(s => s.difficulty.min <= tier && s.difficulty.max >= tier));
    case 'interview': return pick(interviewPool.filter(s => s.difficulty.min <= tier && s.difficulty.max >= tier));
    case 'scope': return pick(scopePool.filter(s => s.difficulty.min <= tier && s.difficulty.max >= tier));
    case 'queryQuest': return pick(queryQuestPool.filter(s => s.difficulty.min <= tier && s.difficulty.max >= tier));
    case 'postmortem': return pick(postmortemPool.filter(s => s.difficulty.min <= tier && s.difficulty.max >= tier));
    case 'trustSafety': return pick(trustSafetyPool.filter(s => s.difficulty.min <= tier && s.difficulty.max >= tier));
    default: return pick(metricsPool);
  }
}